INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0303131F$$, 2026, $$Nuclear Deterrence Operations (NDO) is an Air Force Core Function. Within this core function, Nuclear Command and Control (NC2) is the exercise of authority and
direction by the President, as Commander in Chief, through established command lines, over nuclear weapon operations of military forces. The President's authority
and direction are exercised through the Nuclear Command and Control System (NCCS). The NCCS is the designated combination of flexible and enduring elements
including facilities, equipment, communications, procedures, personnel, and the structure in which these elements are integrated, all of which are essential for planning,
directing, and controlling nuclear weapon operations.

 The Minimum Essential Emergency Communications Network (MEECN) portfolio modernizes the systems necessary to effectively provide assured communications
 connectivity between the President and the strategic deterrence forces in stressed environments.

 MEECN System Improvements (MSI) is a long-range planning effort with users (Air Force Global Strike Command (AFGSC), Air Combat Command (ACC), United
 States Space Force (USSF), Air Mobility Command (AMC), Air Force Special Operations Command (AFSOC), US Strategic Command (USSTRATCOM), and the
 US Navy (USN)) to monitor and assess the performance of existing NC3 systems and develop recommendations for strategic and tactical architecture upgrades,
 requirements, and issues based on available and emerging technologies. MSI is used to conduct technology testing; model performance; analyze technology strategies;
 conduct requirement trade space analysis, technology maturation and risk reduction efforts, and mission analysis; and build technology roadmaps as proactive support
 to the NC3 community. MSI performs analysis, integration, and testing activities for the NC3 Weapon System.

